import React, { useState, useRef } from 'react';
import html2canvas from 'html2canvas';

const LOGOS = {
  ba: "data:image/png;base64,",
  ezra: "data:image/png;base64,",
  ariel: "data:image/png;base64,"
};
export default function App() {
  const posterRef = useRef(null);
  const fileInputRef = useRef(null);

  const [bgColor, setBgColor] = useState('#f2f9f1');
  const [textColor, setTextColor] = useState('#111827');
  const [parasha, setParasha] = useState('פרשת השבוע');
  const [footerText, setFooterText] = useState('צוות הדרכה');
  const [selectedMovement, setSelectedMovement] = useState('ba');
  const [customLogo, setCustomLogo] = useState('');
  const [schedule, setSchedule] = useState([
    { id: 1, name: 'כניסת שבת', time: '19:30', active: true },
    { id: 2, name: 'פעולת חב"ב', time: '21:00', active: true },
    { id: 3, name: 'מפקד', time: '15:45', active: true },
    { id: 4, name: 'מנחה', time: '16:00', active: true },
    { id: 5, name: 'פעולות', time: '16:30', active: true },
    { id: 6, name: 'סד"ש', time: '18:00', active: true },
    { id: 7, name: 'ערבית', time: '19:45', active: true },
    { id: 8, name: 'מוצ"ש', time: '20:30', active: true }
  ]);

  const updateItem = (id, field, value) => {
    setSchedule(schedule.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const addItem = () => setSchedule([...schedule, { id: Date.now(), name: 'זמן חדש', time: '00:00', active: true }]);
  const deleteItem = (id) => setSchedule(schedule.filter(item => item.id !== id));

  const handleFile = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setCustomLogo(event.target.result); setSelectedMovement('custom'); };
      reader.readAsDataURL(file);
    }
  };

  const handleDownload = async () => {
    if (posterRef.current) {
      const canvas = await html2canvas(posterRef.current, { scale: 2 });
      const link = document.createElement('a');
      link.download = `${parasha}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    }
  };

  const handleShare = async () => {
    if (posterRef.current) {
      const canvas = await html2canvas(posterRef.current, { scale: 2 });
      canvas.toBlob(async (blob) => {
        if (!blob) return;
        const file = new File([blob], 'shabbat.png', { type: 'image/png' });
        if (navigator.canShare && navigator.canShare({ files: [file] })) {
          await navigator.share({ files: [file], title: 'לוח שבת' });
        } else {
          alert('שיתוף לא נתמך בדפדפן זה');
        }
      });
    }
  };

  return (
    <div style={{ 
      direction: 'rtl', 
      padding: '20px', 
      backgroundColor: '#f3f4f6', 
      minHeight: '100vh', 
      display: 'flex', 
      justifyContent: 'center',
      fontFamily: "'Heebo', sans-serif" // גופן מעוצב לכל הממשק
    }}>
      {/* ייבוא הגופן */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Heebo:wght@400;700&display=swap');
      `}</style>
      
      <div style={{ 
        display: 'flex', 
        flexDirection: 'row', 
        gap: '30px', 
        alignItems: 'flex-start', 
        justifyContent: 'center',
        width: '100%',
        maxWidth: '1050px'
      }}>
        
        {/* צד ימין: פאנל הגדרות */}
        <div style={{ width: '400px', flexShrink: 0, backgroundColor: 'white', padding: '25px', borderRadius: '12px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
          <h2 style={{ marginTop: 0 }}>הגדרת לו"ז שבת</h2>

          <div style={{ display: 'flex', gap: '20px', marginBottom: '20px' }}>
            <div style={{ flex: 1 }}>
              <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>צבע רקע</label>
              <input type="color" value={bgColor} onChange={(e) => setBgColor(e.target.value)} style={{ width: '100%', height: '35px', cursor: 'pointer' }} />
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>צבע טקסט</label>
              <input type="color" value={textColor} onChange={(e) => setTextColor(e.target.value)} style={{ width: '100%', height: '35px', cursor: 'pointer' }} />
            </div>
          </div>

          <label style={{ fontWeight: 'bold', marginBottom: '10px', display: 'block' }}>סמל התנועה:</label>
          <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
            {['ba', 'ezra', 'ariel'].map(m => (
              <button key={m} onClick={() => setSelectedMovement(m)} style={{ width: '60px', height: '60px', border: selectedMovement === m ? '3px solid #2563eb' : '1px solid #ccc', borderRadius: '8px', cursor: 'pointer', overflow: 'hidden', padding: '4px' }}>
                <img src={LOGOS[m]} style={{ width: '100%', height: '100%', objectFit: 'contain' }} alt={m} />
              </button>
            ))}
            <button onClick={() => fileInputRef.current.click()} style={{ width: '60px', height: '60px', border: '1px dashed #999', borderRadius: '8px', cursor: 'pointer' }}>+</button>
            <input type="file" ref={fileInputRef} onChange={handleFile} style={{ display: 'none' }} />
          </div>

          <label style={{ fontWeight: 'bold', marginBottom: '5px', display: 'block' }}>פרשת השבוע:</label>
          <input type="text" value={parasha} onChange={(e) => setParasha(e.target.value)} style={{ width: '100%', padding: '10px', marginBottom: '15px', boxSizing: 'border-box', fontFamily: 'inherit' }} placeholder="שם הפרשה" />
          
          <label style={{ fontWeight: 'bold', marginBottom: '5px', display: 'block' }}>כיתוב תחתון:</label>
          <input type="text" value={footerText} onChange={(e) => setFooterText(e.target.value)} style={{ width: '100%', padding: '10px', marginBottom: '20px', boxSizing: 'border-box', fontFamily: 'inherit' }} placeholder="כיתוב תחתון" />

          <label style={{ fontWeight: 'bold', marginBottom: '10px', display: 'block' }}>לוח זמנים:</label>
          <div style={{ marginBottom: '20px' }}>
            {schedule.map(item => (
              <div key={item.id} style={{ display: 'flex', gap: '5px', marginBottom: '5px' }}>
                <input type="checkbox" checked={item.active} onChange={(e) => updateItem(item.id, 'active', e.target.checked)} />
                <input type="time" value={item.time} onChange={(e) => updateItem(item.id, 'time', e.target.value)} style={{ width: '80px', fontFamily: 'inherit' }} />
                <input type="text" value={item.name} onChange={(e) => updateItem(item.id, 'name', e.target.value)} style={{ flex: 1, fontFamily: 'inherit' }} />
                <button onClick={() => deleteItem(item.id)} style={{ border: 'none', cursor: 'pointer', background: 'transparent' }}>🗑️</button>
              </div>
            ))}
            <button onClick={addItem} style={{ width: '100%', marginTop: '5px', padding: '8px', cursor: 'pointer', backgroundColor: '#e5e7eb', border: 'none', borderRadius: '5px' }}>+ הוסף זמן</button>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            <button onClick={handleShare} style={{ width: '100%', padding: '12px', background: '#059669', color: 'white', border: 'none', borderRadius: '5px', fontWeight: 'bold', cursor: 'pointer' }}>📤 שיתוף</button>
            <div style={{ display: 'flex', gap: '10px' }}>
                <button onClick={handleDownload} style={{ flex: 1, padding: '12px', background: '#2563eb', color: 'white', border: 'none', borderRadius: '5px', fontWeight: 'bold', cursor: 'pointer' }}>⬇️ הורדה</button>
                <button onClick={() => window.print()} style={{ flex: 1, padding: '12px', background: '#374151', color: 'white', border: 'none', borderRadius: '5px', fontWeight: 'bold', cursor: 'pointer' }}>🖨️ הדפסה</button>
            </div>
          </div>
        </div>

        {/* צד שמאל: פוסטר */}
        <div ref={posterRef} style={{ width: '550px', flexShrink: 0, height: '778px', padding: '50px', borderRadius: '16px', backgroundColor: bgColor, color: textColor, position: 'relative', display: 'flex', flexDirection: 'column', alignItems: 'center', boxShadow: '0 10px 15px rgba(0,0,0,0.1)' }}>
          <div style={{ position: 'absolute', top: '35px', left: '35px', width: '85px', height: '85px', backgroundColor: 'white', borderRadius: '50%', padding: '6px', overflow: 'hidden' }}>
            <img src={selectedMovement === 'custom' ? customLogo : LOGOS[selectedMovement]} alt="" style={{ width: '100%', height: '100%', objectFit: 'contain' }} />
          </div>
          <h1 style={{ fontSize: '54px', marginTop: '50px', fontWeight: 'bold' }}>שבת שלום</h1>
          <h2 style={{ fontSize: '22px', padding: '6px 28px', backgroundColor: 'rgba(255,255,255,0.2)', borderRadius: '25px', fontWeight: 'bold' }}>{parasha}</h2>
          
          <div style={{ width: '100%', marginTop: '20px' }}>
            {schedule.filter(i => i.active).map(i => (
              <div key={i.id} style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '2px dashed rgba(0,0,0,0.1)', padding: '5px 0' }}>
                <span style={{ fontSize: '22px', fontWeight: 'bold' }}>{i.name}</span>
                <span style={{ fontSize: '24px', fontWeight: 'bold' }}>{i.time}</span>
              </div>
            ))}
          </div>
          
          <div style={{ marginTop: 'auto', fontSize: '20px', fontWeight: 'bold', borderTop: '2px solid rgba(0,0,0,0.1)', width: '100%', textAlign: 'center', paddingTop: '15px' }}>{footerText}</div>
        </div>

      </div>
    </div>
  );
}
